from dataclasses import dataclass
from typing import List

@dataclass
class Token:
    kind: str
    value: object
    line: int
    col: int

class Lexer:
    def __init__(self, source: str):
        self.source = source
        self.pos = 0
        self.line = 1
        self.col = 1
        self.tokens = []

    def peek(self) -> str:
        if self.pos >= len(self.source):
            return ''
        return self.source[self.pos]

    def advance(self) -> str:
        if self.pos >= len(self.source):
            return ''
        char = self.source[self.pos]
        self.pos += 1
        if char == '\n':
            self.line += 1
            self.col = 1
        else:
            self.col += 1
        return char

    def skip_whitespace_and_comments(self):
        while True:
            char = self.peek()
            if char == ' ' or char == '\t' or char == '\r':
                self.advance()
            elif char == '/':
                # Check for comment
                self.advance()
                if self.peek() == '/':
                    # Skip comment
                    while self.peek() != '\n' and self.peek() != '':
                        self.advance()
                    # Skip the newline
                    if self.peek() == '\n':
                        self.advance()
                else:
                    # Not a comment, put back the /
                    self.pos -= 1
                    self.col -= 1
                    break
            else:
                break

    def read_number(self) -> Token:
        start_pos = self.pos
        start_col = self.col

        # Read integer part
        while self.peek().isdigit():
            self.advance()

        # Check for decimal point
        if self.peek() == '.':
            self.advance()
            # Read fractional part
            while self.peek().isdigit():
                self.advance()

        # Get the value
        value_str = self.source[start_pos:self.pos]
        value = float(value_str)

        return Token('NUMBER', value, self.line, start_col)

    def read_string(self) -> Token:
        start_pos = self.pos
        start_col = self.col
        self.advance()  # Skip opening quote

        # Read string content
        while True:
            char = self.peek()
            if char == '':
                # Unterminated string
                raise Exception(f"Unterminated string at line {self.line}, column {self.col}")
            elif char == '\n':
                # String cannot span multiple lines
                raise Exception(f"String cannot span multiple lines at line {self.line}, column {self.col}")
            elif char == '"':
                self.advance()  # Skip closing quote
                value_str = self.source[start_pos+1:self.pos-1]  # Exclude quotes
                return Token('STRING', value_str, self.line, start_col)
            elif char == '\\':
                self.advance()  # Skip backslash
                # Skip the escaped character
                self.advance()
            else:
                self.advance()

    def read_identifier_or_keyword(self) -> Token:
        start_pos = self.pos
        start_col = self.col

        # Read identifier
        while self.peek().isalnum() or self.peek() == '_':
            self.advance()

        value_str = self.source[start_pos:self.pos]

        # Check if it's a keyword
        keywords = {
            'let', 'if', 'else', 'while', 'for', 'in', 'fn', 'return',
            'break', 'continue', 'true', 'false', 'nil'
        }

        if value_str in keywords:
            return Token('KEYWORD', value_str, self.line, start_col)
        else:
            return Token('IDENT', value_str, self.line, start_col)

    def read_punctuation(self) -> Token:
        start_pos = self.pos
        start_col = self.col

        char = self.advance()

        # Check for multi-character operators
        if char == '=':
            if self.peek() == '=':
                self.advance()
                return Token('PUNCT', '==', self.line, start_col)
        elif char == '!':
            if self.peek() == '=':
                self.advance()
                return Token('PUNCT', '!=', self.line, start_col)
        elif char == '<':
            if self.peek() == '=':
                self.advance()
                return Token('PUNCT', '<=', self.line, start_col)
        elif char == '>':
            if self.peek() == '=':
                self.advance()
                return Token('PUNCT', '>=', self.line, start_col)
        elif char == '&':
            if self.peek() == '&':
                self.advance()
                return Token('PUNCT', '&&', self.line, start_col)
        elif char == '|':
            if self.peek() == '|':
                self.advance()
                return Token('PUNCT', '||', self.line, start_col)

        # Single character punctuation
        return Token('PUNCT', char, self.line, start_col)

    def tokenize(self) -> List[Token]:
        self.pos = 0
        self.line = 1
        self.col = 1
        self.tokens = []

        while True:
            self.skip_whitespace_and_comments()

            if self.pos >= len(self.source):
                self.tokens.append(Token('EOF', None, self.line, self.col))
                break

            char = self.peek()

            if char.isdigit():
                self.tokens.append(self.read_number())
